using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public interface IInspectionStore
{
    Task<List<ConstructionSite>> GetSitesAsync();
    Task SaveSiteAsync(ConstructionSite site);
    Task DeleteSiteAsync(string siteId);

    Task<List<Inspection>> GetInspectionsAsync(string? siteId = null);
    Task<Inspection?> GetInspectionAsync(string inspectionId);
    Task SaveInspectionAsync(Inspection inspection);
    Task DeleteInspectionAsync(string inspectionId);

    Task<List<Inspection>> GetUnsyncedInspectionsAsync();
    Task MarkAsSyncedAsync(string inspectionId);
}

using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class IndexedDbStore : IInspectionStore
{
    private readonly IJSRuntime _js;
    private readonly JsonSerializerOptions _jsonOptions = new() { PropertyNamingPolicy = JsonNamingPolicy.CamelCase };

    public IndexedDbStore(IJSRuntime js)
    {
        _js = js;
    }

    public async Task<List<ConstructionSite>> GetSitesAsync()
    {
        var json = await _js.InvokeAsync<string>("inspectionDb.getAll", "sites");
        return JsonSerializer.Deserialize<List<ConstructionSite>>(json, _jsonOptions) ?? new();
    }

    public async Task SaveSiteAsync(ConstructionSite site)
    {
        var json = JsonSerializer.Serialize(site, _jsonOptions);
        await _js.InvokeVoidAsync("inspectionDb.put", "sites", site.Id, json);
    }

    public async Task DeleteSiteAsync(string siteId)
    {
        await _js.InvokeVoidAsync("inspectionDb.delete", "sites", siteId);
    }

    public async Task<List<Inspection>> GetInspectionsAsync(string? siteId = null)
    {
        var json = await _js.InvokeAsync<string>("inspectionDb.getAll", "inspections");
        var inspections = JsonSerializer.Deserialize<List<Inspection>>(json, _jsonOptions) ?? new();
        if (siteId is not null)
            inspections = inspections.Where(i => i.SiteId == siteId).ToList();
        return inspections.OrderByDescending(i => i.InspectionDate).ToList();
    }

    public async Task<Inspection?> GetInspectionAsync(string inspectionId)
    {
        var json = await _js.InvokeAsync<string?>("inspectionDb.get", "inspections", inspectionId);
        if (json is null) return null;
        return JsonSerializer.Deserialize<Inspection>(json, _jsonOptions);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var json = JsonSerializer.Serialize(inspection, _jsonOptions);
        await _js.InvokeVoidAsync("inspectionDb.put", "inspections", inspection.Id, json);
    }

    public async Task DeleteInspectionAsync(string inspectionId)
    {
        await _js.InvokeVoidAsync("inspectionDb.delete", "inspections", inspectionId);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var all = await GetInspectionsAsync();
        return all.Where(i => !i.IsSynced && i.Status == InspectionStatus.Completed).ToList();
    }

    public async Task MarkAsSyncedAsync(string inspectionId)
    {
        var inspection = await GetInspectionAsync(inspectionId);
        if (inspection is not null)
        {
            inspection.IsSynced = true;
            await SaveInspectionAsync(inspection);
        }
    }
}

using Microsoft.JSInterop;

namespace SiteInspector.Client.Services;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;
    private bool _isOnline = true;

    public bool IsOnline => _isOnline;
    public event Action? OnConnectivityChanged;

    public ConnectivityService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        _isOnline = await _js.InvokeAsync<bool>("connectivityMonitor.initialize", _dotNetRef);
    }

    [JSInvokable]
    public void OnStatusChanged(bool isOnline)
    {
        _isOnline = isOnline;
        OnConnectivityChanged?.Invoke();
    }

    public async ValueTask DisposeAsync()
    {
        if (_dotNetRef is not null)
        {
            await _js.InvokeVoidAsync("connectivityMonitor.dispose");
            _dotNetRef.Dispose();
        }
    }
}

using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService
{
    private readonly IInspectionStore _store;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private bool _isSyncing;

    public int PendingSyncCount { get; private set; }
    public event Action? OnSyncStateChanged;

    public SyncService(IInspectionStore store, ConnectivityService connectivity, HttpClient http)
    {
        _store = store;
        _connectivity = connectivity;
        _http = http;
        _connectivity.OnConnectivityChanged += async () => await TrySyncAsync();
    }

    public async Task UpdatePendingCountAsync()
    {
        var unsynced = await _store.GetUnsyncedInspectionsAsync();
        PendingSyncCount = unsynced.Count;
        OnSyncStateChanged?.Invoke();
    }

    public async Task TrySyncAsync()
    {
        if (_isSyncing || !_connectivity.IsOnline) return;
        _isSyncing = true;

        try
        {
            var unsynced = await _store.GetUnsyncedInspectionsAsync();
            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("/api/inspections/sync", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _store.MarkAsSyncedAsync(inspection.Id);
                    }
                }
                catch
                {
                    // Server unreachable — stop trying remaining items
                    break;
                }
            }
        }
        finally
        {
            _isSyncing = false;
            await UpdatePendingCountAsync();
        }
    }
}

