using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class IndexedDbStore : IInspectionStore
{
    private readonly IJSRuntime _js;
    private readonly JsonSerializerOptions _jsonOptions = new() { PropertyNamingPolicy = JsonNamingPolicy.CamelCase };

    public IndexedDbStore(IJSRuntime js)
    {
        _js = js;
    }

    public async Task<List<ConstructionSite>> GetSitesAsync()
    {
        var json = await _js.InvokeAsync<string>("inspectionDb.getAll", "sites");
        return JsonSerializer.Deserialize<List<ConstructionSite>>(json, _jsonOptions) ?? new();
    }

    public async Task SaveSiteAsync(ConstructionSite site)
    {
        var json = JsonSerializer.Serialize(site, _jsonOptions);
        await _js.InvokeVoidAsync("inspectionDb.put", "sites", site.Id, json);
    }

    public async Task DeleteSiteAsync(string siteId)
    {
        await _js.InvokeVoidAsync("inspectionDb.delete", "sites", siteId);
    }

    public async Task<List<Inspection>> GetInspectionsAsync(string? siteId = null)
    {
        var json = await _js.InvokeAsync<string>("inspectionDb.getAll", "inspections");
        var inspections = JsonSerializer.Deserialize<List<Inspection>>(json, _jsonOptions) ?? new();
        if (siteId is not null)
            inspections = inspections.Where(i => i.SiteId == siteId).ToList();
        return inspections.OrderByDescending(i => i.InspectionDate).ToList();
    }

    public async Task<Inspection?> GetInspectionAsync(string inspectionId)
    {
        var json = await _js.InvokeAsync<string?>("inspectionDb.get", "inspections", inspectionId);
        if (json is null) return null;
        return JsonSerializer.Deserialize<Inspection>(json, _jsonOptions);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var json = JsonSerializer.Serialize(inspection, _jsonOptions);
        await _js.InvokeVoidAsync("inspectionDb.put", "inspections", inspection.Id, json);
    }

    public async Task DeleteInspectionAsync(string inspectionId)
    {
        await _js.InvokeVoidAsync("inspectionDb.delete", "inspections", inspectionId);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var all = await GetInspectionsAsync();
        return all.Where(i => !i.IsSynced && i.Status == InspectionStatus.Completed).ToList();
    }

    public async Task MarkAsSyncedAsync(string inspectionId)
    {
        var inspection = await GetInspectionAsync(inspectionId);
        if (inspection is not null)
        {
            inspection.IsSynced = true;
            await SaveInspectionAsync(inspection);
        }
    }
}
"}

