namespace SiteInspector.Client.Services;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;
    private bool _isOnline = true;

    public bool IsOnline => _isOnline;
    public event Action? OnConnectivityChanged;

    public ConnectivityService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        _isOnline = await _js.InvokeAsync<bool>("connectivityMonitor.initialize", _dotNetRef);
    }

    [JSInvokable]
    public void OnStatusChanged(bool isOnline)
    {
        _isOnline = isOnline;
        OnConnectivityChanged?.Invoke();
    }

    public async ValueTask DisposeAsync()
    {
        if (_dotNetRef is not null)
        {
            await _js.InvokeVoidAsync("connectivityMonitor.dispose");
            _dotNetRef.Dispose();
        }
    }
}
"}

