using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService
{
    private readonly IInspectionStore _store;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private bool _isSyncing;

    public int PendingSyncCount { get; private set; }
    public event Action? OnSyncStateChanged;

    public SyncService(IInspectionStore store, ConnectivityService connectivity, HttpClient http)
    {
        _store = store;
        _connectivity = connectivity;
        _http = http;
        _connectivity.OnConnectivityChanged += async () => await TrySyncAsync();
    }

    public async Task UpdatePendingCountAsync()
    {
        var unsynced = await _store.GetUnsyncedInspectionsAsync();
        PendingSyncCount = unsynced.Count;
        OnSyncStateChanged?.Invoke();
    }

    public async Task TrySyncAsync()
    {
        if (_isSyncing || !_connectivity.IsOnline) return;
        _isSyncing = true;

        try
        {
            var unsynced = await _store.GetUnsyncedInspectionsAsync();
            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("/api/inspections/sync", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _store.MarkAsSyncedAsync(inspection.Id);
                    }
                }
                catch
                {
                    // Server unreachable — stop trying remaining items
                    break;
                }
            }
        }
        finally
        {
            _isSyncing = false;
            await UpdatePendingCountAsync();
        }
    }
}

