@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private ConstructionSite? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        var sites = await Store.GetSitesAsync();
        _site = sites.FirstOrDefault(s => s.Id == SiteId);
        _inspections = await Store.GetInspectionsAsync(SiteId);
    }

    private async Task StartInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = _site?.Name ?? "Unknown",
            Checklist = SafetyChecklist.GetDefaultChecklist()
        };
        await Store.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }

    private string GetStatusBadge(Inspection inspection) =>
        inspection.Status == InspectionStatus.Completed ? "bg-success" : "bg-info";

    private string GetChecklistSummary(Inspection inspection)
    {
        var total = inspection.Checklist.Count;
        var checked_ = inspection.Checklist.Count(c => c.Result != CheckResult.NotChecked);
        return $"{checked_}/{total} items checked";
    }
}
