// IndexedDB wrapper for offline inspection storage
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                database.createObjectStore('inspections', { keyPath: 'id' });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.inspectionDb = {
    async getAll(storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.getAll();
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = () => reject(request.error);
        });
    },

    async get(storeName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.get(key);
            request.onsuccess = () => resolve(request.result ? JSON.stringify(request.result) : null);
            request.onerror = () => reject(request.error);
        });
    },

    async put(storeName, key, json) {
        const database = await openDb();
        const obj = JSON.parse(json);
        obj.id = key;
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            const request = store.put(obj);
            request.onsuccess = () => resolve();
            request.onerror = () => reject(request.error);
        });
    },

    async delete(storeName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            const request = store.delete(key);
            request.onsuccess = () => resolve();
            request.onerror = () => reject(request.error);
        });
    }
};

// Connectivity monitor
let dotNetRef = null;

window.connectivityMonitor = {
    initialize(ref) {
        dotNetRef = ref;
        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('OnStatusChanged', true));
        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('OnStatusChanged', false));
        return navigator.onLine;
    },
    dispose() {
        dotNetRef = null;
    }
};

// Photo capture helper
window.photoHelper = {
    async readFileAsBase64(inputElement) {
        const file = inputElement.files[0];
        if (!file) return null;
        return new Promise((resolve) => {
            const reader = new FileReader();
            reader.onload = () => {
                const base64 = reader.result.split(',')[1];
                resolve(JSON.stringify({
                    fileName: file.name,
                    contentType: file.type,
                    base64Data: base64
                }));
            };
            reader.readAsDataURL(file);
        });
    }
};

@page "/"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject IInspectionStore Store
@inject NavigationManager Nav

<PageTitle>Site Inspector</PageTitle>

<div class="page-header">
    <h1>Construction Sites</h1>
    <button class="btn btn-primary btn-lg" @onclick="ShowAddSite">
        <span class="icon">+</span> Add Site
    </button>
</div>

@if (_showAddForm)
{
    <div class="card add-form">
        <div class="card-body">
            <div class="mb-3">
                <input type="text" class="form-control form-control-lg" placeholder="Site name"
                       @bind="_newSiteName" @bind:event="oninput" />
            </div>
            <div class="mb-3">
                <input type="text" class="form-control" placeholder="Address"
                       @bind="_newSiteAddress" @bind:event="oninput" />
            </div>
            <div class="d-flex gap-2">
                <button class="btn btn-success" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">Save</button>
                <button class="btn btn-secondary" @onclick="() => _showAddForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

@if (_sites is null)
{
    <div class="loading">Loading sites...</div>
}
else if (_sites.Count == 0)
{
    <div class="empty-state">
        <div class="empty-icon">🏗️</div>
        <p>No construction sites yet.</p>
        <p>Tap <strong>Add Site</strong> to get started.</p>
    </div>
}
else
{
    <div class="site-list">
        @foreach (var site in _sites)
        {
            <div class="site-card" @onclick="() => Nav.NavigateTo($&quot;/site/{site.Id}&quot;)">
                <div class="site-card-body">
                    <h3>@site.Name</h3>
                    <p class="text-muted">@site.Address</p>
                </div>
                <div class="site-card-arrow">›</div>
            </div>
        }
    </div>
}

@code {
    private List<ConstructionSite>? _sites;
    private bool _showAddForm;
    private string _newSiteName = string.Empty;
    private string _newSiteAddress = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        _sites = await Store.GetSitesAsync();
    }

    private void ShowAddSite()
    {
        _showAddForm = true;
        _newSiteName = string.Empty;
        _newSiteAddress = string.Empty;
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new ConstructionSite
        {
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim()
        };
        await Store.SaveSiteAsync(site);
        _sites = await Store.GetSitesAsync();
        _showAddForm = false;
    }
}

