@page "/site/{SiteId}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject IInspectionStore Store
@inject NavigationManager Nav

<PageTitle>Site Details</PageTitle>

<div class="page-header">
    <button class="btn btn-outline-secondary btn-back" @onclick="() => Nav.NavigateTo(&quot;/&quot;)">← Back</button>
    <h1>@_site?.Name</h1>
</div>

@if (_site is null)
{
    <div class="loading">Loading...</div>
}
else
{
    <div class="site-info mb-3">
        <p class="text-muted">@_site.Address</p>
    </div>

    <button class="btn btn-primary btn-lg w-100 mb-4" @onclick="StartInspection">
        🔍 Start New Inspection
    </button>

    <h2>Past Inspections</h2>

    @if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <p>No inspections yet for this site.</p>
        </div>
    }
    else
    {
        <div class="inspection-list">
            @foreach (var inspection in _inspections)
            {
                <div class="inspection-card" @onclick="() => Nav.NavigateTo($&quot;/inspection/{inspection.Id}&quot;)">
                    <div class="inspection-card-body">
                        <div class="inspection-date">@inspection.InspectionDate.ToString("MMM dd, yyyy h:mm tt")</div>
                        <div class="inspection-inspector">@inspection.InspectorName</div>
                        <div class="inspection-meta">
                            <span class="badge @GetStatusBadge(inspection)">@inspection.Status</span>
                            @if (!inspection.IsSynced)
                            {
                                <span class="badge bg-warning">Not synced</span>
                            }
                            <span class="text-muted">@GetChecklistSummary(inspection)</span>
                        </div>
                    </div>
                    <div class="site-card-arrow">›</div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private ConstructionSite? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        var sites = await Store.GetSitesAsync();
        _site = sites.FirstOrDefault(s => s.Id == SiteId);
        _inspections = await Store.GetInspectionsAsync(SiteId);
    }

    private async Task StartInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = _site?.Name ?? "Unknown",
            Checklist = SafetyChecklist.GetDefaultChecklist()
        };
        await Store.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }

    private string GetStatusBadge(Inspection inspection) =>
        inspection.Status == InspectionStatus.Completed ? "bg-success" : "bg-info";

    private string GetChecklistSummary(Inspection inspection)
    {
        var total = inspection.Checklist.Count;
        var checked_ = inspection.Checklist.Count(c => c.Result != CheckResult.NotChecked);
        return $"{checked_}/{total} items checked";
    }
}

