@page "/inspection/{InspectionId}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject IInspectionStore Store
@inject SyncService Sync
@inject NavigationManager Nav
@inject IJSRuntime JS

<PageTitle>Inspection</PageTitle>

<div class="page-header compact">
    <button class="btn btn-outline-secondary btn-back" @onclick="GoBack">← Back</button>
    <div class="header-actions">
        @if (_inspection?.Status == InspectionStatus.InProgress)
        {
            <button class="btn btn-success" @onclick="CompleteInspection">✓ Complete</button>
        }
    </div>
</div>

@if (_inspection is null)
{
    <div class="loading">Loading...</div>
}
else
{
    <div class="inspection-header">
        <h2>@_inspection.SiteName</h2>
        <p class="text-muted">@_inspection.InspectionDate.ToString("MMM dd, yyyy h:mm tt")</p>
    </div>

    <div class="mb-3">
        <input type="text" class="form-control form-control-lg" placeholder="Inspector name"
               value="@_inspection.InspectorName"
               @onchange="OnInspectorNameChanged" />
    </div>

    <!-- Tab navigation -->
    <ul class="nav nav-tabs inspection-tabs">
        <li class="nav-item">
            <button class="nav-link @(_activeTab == "checklist" ? "active" : "")"
                    @onclick="() => _activeTab = &quot;checklist&quot;">
                Checklist <span class="badge bg-secondary">@GetProgress()</span>
            </button>
        </li>
        <li class="nav-item">
            <button class="nav-link @(_activeTab == "photos" ? "active" : "")"
                    @onclick="() => _activeTab = &quot;photos&quot;">
                Photos <span class="badge bg-secondary">@_inspection.Photos.Count</span>
            </button>
        </li>
        <li class="nav-item">
            <button class="nav-link @(_activeTab == "notes" ? "active" : "")"
                    @onclick="() => _activeTab = &quot;notes&quot;">
                Notes
            </button>
        </li>
    </ul>

    <div class="tab-content">
        @if (_activeTab == "checklist")
        {
            @foreach (var category in _inspection.Checklist.Select(c => c.Category).Distinct())
            {
                <div class="checklist-category">
                    <h4>@category</h4>
                    @foreach (var item in _inspection.Checklist.Where(c => c.Category == category))
                    {
                        <div class="checklist-item @GetItemClass(item)">
                            <div class="checklist-item-text">
                                <span>@item.Description</span>
                                @if (!string.IsNullOrEmpty(item.Notes))
                                {
                                    <small class="text-muted d-block">📝 @item.Notes</small>
                                }
                            </div>
                            <div class="checklist-actions">
                                <button class="btn-check-result @(item.Result == CheckResult.Pass ? "active-pass" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Pass)" title="Pass">✓</button>
                                <button class="btn-check-result @(item.Result == CheckResult.Fail ? "active-fail" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Fail)" title="Fail">✗</button>
                                <button class="btn-check-result @(item.Result == CheckResult.NotApplicable ? "active-na" : "")"
                                        @onclick="() => SetResult(item, CheckResult.NotApplicable)" title="N/A">—</button>
                                <button class="btn-check-result btn-note"
                                        @onclick="() => ToggleItemNote(item)" title="Add note">📝</button>
                            </div>
                        </div>
                        @if (_editingNoteItemId == item.Id)
                        {
                            <div class="item-note-editor">
                                <input type="text" class="form-control" placeholder="Add note for this item..."
                                       value="@item.Notes" @onchange="e => OnItemNoteChanged(item, e)" />
                            </div>
                        }
                    }
                </div>
            }
        }
        else if (_activeTab == "photos")
        {
            <div class="photo-section">
                <div class="photo-capture">
                    <label class="btn btn-outline-primary btn-lg w-100">
                        📷 Take Photo / Choose from Gallery
                        <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment"
                                   class="d-none" />
                    </label>
                </div>

                @if (_inspection.Photos.Count == 0)
                {
                    <div class="empty-state">
                        <p>No photos attached yet.</p>
                    </div>
                }
                else
                {
                    <div class="photo-grid">
                        @foreach (var photo in _inspection.Photos)
                        {
                            <div class="photo-card">
                                <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" />
                                <div class="photo-caption">
                                    <input type="text" class="form-control form-control-sm" placeholder="Caption..."
                                           value="@photo.Caption"
                                           @onchange="e => OnPhotoCaptionChanged(photo, e)" />
                                </div>
                                <button class="btn btn-sm btn-danger photo-delete"
                                        @onclick="() => RemovePhoto(photo)">🗑️</button>
                            </div>
                        }
                    </div>
                }
            </div>
        }
        else if (_activeTab == "notes")
        {
            <div class="notes-section">
                <textarea class="form-control" rows="8" placeholder="General inspection notes..."
                          @onchange="OnNotesChanged">@_inspection.Notes</textarea>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string InspectionId { get; set; } = string.Empty;

    private Inspection? _inspection;
    private string _activeTab = "checklist";
    private string? _editingNoteItemId;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Store.GetInspectionAsync(InspectionId);
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = item.Result == result ? CheckResult.NotChecked : result;
        await SaveAsync();
    }

    private void ToggleItemNote(ChecklistItem item)
    {
        _editingNoteItemId = _editingNoteItemId == item.Id ? null : item.Id;
    }

    private async Task OnItemNoteChanged(ChecklistItem item, ChangeEventArgs e)
    {
        item.Notes = e.Value?.ToString() ?? string.Empty;
        _editingNoteItemId = null;
        await SaveAsync();
    }

    private async Task OnInspectorNameChanged(ChangeEventArgs e)
    {
        if (_inspection is null) return;
        _inspection.InspectorName = e.Value?.ToString() ?? string.Empty;
        await SaveAsync();
    }

    private async Task OnNotesChanged(ChangeEventArgs e)
    {
        if (_inspection is null) return;
        _inspection.Notes = e.Value?.ToString() ?? string.Empty;
        await SaveAsync();
    }

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        if (_inspection is null) return;

        var file = e.File;
        const long maxSize = 10 * 1024 * 1024; // 10MB
        using var stream = file.OpenReadStream(maxSize);
        using var ms = new System.IO.MemoryStream();
        await stream.CopyToAsync(ms);

        var photo = new PhotoAttachment
        {
            FileName = file.Name,
            ContentType = file.ContentType,
            Base64Data = Convert.ToBase64String(ms.ToArray()),
            CapturedAt = DateTime.UtcNow
        };
        _inspection.Photos.Add(photo);
        await SaveAsync();
    }

    private async Task OnPhotoCaptionChanged(PhotoAttachment photo, ChangeEventArgs e)
    {
        photo.Caption = e.Value?.ToString() ?? string.Empty;
        await SaveAsync();
    }

    private async Task RemovePhoto(PhotoAttachment photo)
    {
        _inspection?.Photos.Remove(photo);
        await SaveAsync();
    }

    private async Task CompleteInspection()
    {
        if (_inspection is null) return;
        _inspection.Status = InspectionStatus.Completed;
        await SaveAsync();
        await Sync.UpdatePendingCountAsync();
        await Sync.TrySyncAsync();
    }

    private async Task SaveAsync()
    {
        if (_inspection is not null)
            await Store.SaveInspectionAsync(_inspection);
    }

    private void GoBack()
    {
        if (_inspection is not null)
            Nav.NavigateTo($"/site/{_inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }

    private string GetProgress()
    {
        if (_inspection is null) return "0/0";
        var total = _inspection.Checklist.Count;
        var done = _inspection.Checklist.Count(c => c.Result != CheckResult.NotChecked);
        return $"{done}/{total}";
    }

    private string GetItemClass(ChecklistItem item) => item.Result switch
    {
        CheckResult.Pass => "item-pass",
        CheckResult.Fail => "item-fail",
        CheckResult.NotApplicable => "item-na",
        _ => ""
    };
}

