﻿@inherits LayoutComponentBase
@using SiteInspector.Client.Services
@inject ConnectivityService Connectivity
@inject SyncService Sync

<div class="app-container">
    <header class="app-header">
        <div class="header-brand">🏗️ Site Inspector</div>
        <div class="header-status">
            @if (!Connectivity.IsOnline)
            {
                <span class="status-badge offline">Offline</span>
            }
            else if (Sync.PendingSyncCount > 0)
            {
                <button class="status-badge syncing" @onclick="DoSync">
                    ↑ @Sync.PendingSyncCount to sync
                </button>
            }
            else
            {
                <span class="status-badge online">Online</span>
            }
        </div>
    </header>

    <main class="app-main">
        @Body
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    protected override void OnInitialized()
    {
        Connectivity.OnConnectivityChanged += StateHasChanged;
        Sync.OnSyncStateChanged += StateHasChanged;
    }

    private async Task DoSync()
    {
        await Sync.TrySyncAsync();
    }
}

