arguments.new_str:
using SiteInspector.Client.Models;
using SiteInspector.Client.Pages;
using SiteInspector.Components;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveWebAssemblyComponents();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseAntiforgery();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(SiteInspector.Client._Imports).Assembly);

// Sync API endpoint — receives completed inspections from offline clients
app.MapPost("/api/inspections/sync", (Inspection inspection) =>
{
    // In production, persist to a database. For now, log and acknowledge.
    Console.WriteLine($"Synced inspection {inspection.Id} for site {inspection.SiteName} ({inspection.Checklist.Count} items, {inspection.Photos.Count} photos)");
    return Results.Ok(new { synced = true, id = inspection.Id });
});

app.MapGet("/api/inspections", () =>
{
    // Placeholder — in production, return inspections from database
    return Results.Ok(Array.Empty<Inspection>());
});

app.Run();

