arguments.new_str:
html, body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    margin: 0;
    padding: 0;
    -webkit-tap-highlight-color: transparent;
    overscroll-behavior: none;
}

a, .btn-link {
    color: #006bb7;
}

.btn-primary {
    color: #fff;
    background-color: #e94560;
    border-color: #d63851;
}

.btn-primary:hover, .btn-primary:active {
    background-color: #d63851;
    border-color: #c22d44;
}

.btn:focus, .btn:active:focus, .btn-link.nav-link:focus, .form-control:focus, .form-check-input:focus {
    box-shadow: 0 0 0 0.1rem white, 0 0 0 0.25rem #e94560;
}

/* Page header */
.page-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 1rem;
    gap: 0.5rem;
}
.page-header h1 {
    font-size: 1.4rem;
    margin: 0;
    flex: 1;
}
.btn-back {
    padding: 0.25rem 0.5rem;
    font-size: 1rem;
}
.page-header.compact {
    margin-bottom: 0.5rem;
}
.header-actions {
    display: flex;
    gap: 0.5rem;
}

/* Site cards */
.site-card, .inspection-card {
    display: flex;
    align-items: center;
    padding: 1rem;
    margin-bottom: 0.5rem;
    border-radius: 0.5rem;
    background: #fff;
    border: 1px solid #e0e0e0;
    cursor: pointer;
    transition: background 0.1s;
    -webkit-tap-highlight-color: transparent;
}
.site-card:active, .inspection-card:active {
    background: #f0f0f0;
}
.site-card-body, .inspection-card-body {
    flex: 1;
}
.site-card h3 {
    margin: 0 0 0.25rem;
    font-size: 1.1rem;
}
.site-card p {
    margin: 0;
    font-size: 0.85rem;
}
.site-card-arrow {
    font-size: 1.5rem;
    color: #aaa;
    padding-left: 0.5rem;
}

/* Inspection cards */
.inspection-date { font-weight: 600; }
.inspection-inspector { font-size: 0.85rem; color: #666; }
.inspection-meta { margin-top: 0.25rem; display: flex; gap: 0.5rem; align-items: center; flex-wrap: wrap; }

/* Checklist */
.checklist-category {
    margin-bottom: 1.5rem;
}
.checklist-category h4 {
    font-size: 0.9rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #666;
    border-bottom: 1px solid #eee;
    padding-bottom: 0.25rem;
    margin-bottom: 0.5rem;
}
.checklist-item {
    display: flex;
    align-items: center;
    padding: 0.6rem 0.5rem;
    border-radius: 0.375rem;
    margin-bottom: 0.25rem;
    gap: 0.5rem;
}
.checklist-item.item-pass { background: #d4edda; }
.checklist-item.item-fail { background: #f8d7da; }
.checklist-item.item-na { background: #e2e3e5; }
.checklist-item-text {
    flex: 1;
    font-size: 0.9rem;
}
.checklist-actions {
    display: flex;
    gap: 0.25rem;
}
.btn-check-result {
    width: 2.2rem;
    height: 2.2rem;
    border: 2px solid #ccc;
    border-radius: 0.375rem;
    background: #fff;
    font-size: 1rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    -webkit-tap-highlight-color: transparent;
}
.btn-check-result:active { transform: scale(0.95); }
.btn-check-result.active-pass { background: #28a745; color: #fff; border-color: #28a745; }
.btn-check-result.active-fail { background: #dc3545; color: #fff; border-color: #dc3545; }
.btn-check-result.active-na { background: #6c757d; color: #fff; border-color: #6c757d; }
.btn-check-result.btn-note { border-color: #ffc107; }

.item-note-editor {
    padding: 0.25rem 0.5rem 0.5rem 2rem;
}

/* Tabs */
.inspection-tabs {
    margin-bottom: 1rem;
}
.inspection-tabs .nav-link {
    font-size: 0.9rem;
    padding: 0.5rem 0.75rem;
}

/* Photos */
.photo-section { margin-top: 0.5rem; }
.photo-capture { margin-bottom: 1rem; }
.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
    gap: 0.75rem;
}
.photo-card {
    position: relative;
    border-radius: 0.5rem;
    overflow: hidden;
    border: 1px solid #ddd;
}
.photo-card img {
    width: 100%;
    aspect-ratio: 1;
    object-fit: cover;
}
.photo-caption {
    padding: 0.25rem;
}
.photo-delete {
    position: absolute;
    top: 0.25rem;
    right: 0.25rem;
}

/* Notes */
.notes-section textarea {
    font-size: 1rem;
    min-height: 200px;
}

/* Empty state */
.empty-state {
    text-align: center;
    padding: 2rem 1rem;
    color: #888;
}
.empty-icon {
    font-size: 3rem;
    margin-bottom: 0.5rem;
}

/* Loading */
.loading {
    text-align: center;
    padding: 2rem;
    color: #888;
}

/* Add form */
.add-form {
    margin-bottom: 1rem;
}

/* Badge overrides for touch */
.badge {
    font-size: 0.7rem;
}

/* Large touch targets */
.btn-lg {
    min-height: 48px;
    font-size: 1rem;
}
.form-control-lg {
    min-height: 48px;
}

.blazor-error-boundary {
    background: url(data:image/svg+xml;base64,) no-repeat 1rem/1.8rem, #b32121;
    padding: 1rem 1rem 1rem 3.7rem;
    color: white;
}

    .blazor-error-boundary::after {
        content: "An error has occurred."
    }

