import base64
# Generate minimal 1x1 PNG as placeholder icons
import struct, zlib
def make_png(size):
    width = height = size
    # RGBA orange pixel
    raw = b''
    for y in range(height):
        raw += b'\x00'  # filter byte
        for x in range(width):
            raw += b'\xe9\x45\x60\xff'  # RGBA
    def chunk(ctype, data):
        c = ctype + data
        return struct.pack('>I', len(data)) + c + struct.pack('>I', zlib.crc32(c) & 0xffffffff)
    ihdr = struct.pack('>IIBBBBB', width, height, 8, 6, 0, 0, 0)
    return b'\x89PNG\r\n\x1a\n' + chunk(b'IHDR', ihdr) + chunk(b'IDAT', zlib.compress(raw)) + chunk(b'IEND', b'')
with open('icon-192.png', 'wb') as f:
    f.write(make_png(192))
with open('icon-512.png', 'wb') as f:
    f.write(make_png(512))
print('Icons created')
"", "description": "Create placeholder PWA icons", "initial_wait": 10}
